import React from 'react';
import ReactDOM from 'react-dom/client';
import './styles/App.css';
import App from './App';

// #region agent log
fetch('http://127.0.0.1:7242/ingest/b49a5b9a-2f04-451a-86d8-a4294227c5a1',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({location:'index.js:beforeRender',message:'Checking root element and CSS',data:{rootExists:!!document.getElementById('root'),cssLoaded:!!document.querySelector('style[data-emotion]')||!!document.querySelector('link[rel="stylesheet"]')},timestamp:Date.now(),sessionId:'debug-session',runId:'run1',hypothesisId:'B'})}).catch(()=>{});
// #endregion

const root = ReactDOM.createRoot(document.getElementById('root'));

// #region agent log
fetch('http://127.0.0.1:7242/ingest/b49a5b9a-2f04-451a-86d8-a4294227c5a1',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({location:'index.js:render',message:'Rendering App',data:{rootCreated:!!root},timestamp:Date.now(),sessionId:'debug-session',runId:'run1',hypothesisId:'A'})}).catch(()=>{});
// #endregion

root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

// #region agent log
setTimeout(() => { const appEl = document.querySelector('.App'); const navEl = document.querySelector('.navbar'); const heroEl = document.querySelector('.hero'); fetch('http://127.0.0.1:7242/ingest/b49a5b9a-2f04-451a-86d8-a4294227c5a1',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({location:'index.js:afterRender',message:'Post-render DOM check',data:{appExists:!!appEl,navExists:!!navEl,heroExists:!!heroEl,bodyChildren:document.body.children.length},timestamp:Date.now(),sessionId:'debug-session',runId:'run1',hypothesisId:'A'})}).catch(()=>{}); }, 100);
// #endregion
